/**
 * @param {string} text
 * @param {{ toast?: "success" | "error"; onHide?: () => void }} [options]
 *   toast: амжилт/алдааны эвтэйхэн мессеж — 3 сек болоод алга болно.
 */
function setStatus(text, options) {
  options = options || {};
  clearAllStatusTimers();

  const el = document.getElementById("status");
  if (!el) return;

  el.replaceChildren();
  el.className = STATUS_EL_DEFAULT;

  const toastKind = options.toast;
  if (toastKind === "success" || toastKind === "error") {
    const iconClass = toastKind === "success" ? "fa-circle-check" : "fa-circle-exclamation";
    const iconColor = toastKind === "success" ? "text-emerald-500" : "text-rose-500";
    const icon = document.createElement("i");
    icon.className = `fa-solid ${iconClass} text-lg shrink-0 ${iconColor}`;
    icon.setAttribute("aria-hidden", "true");
    const span = document.createElement("span");
    span.className = "flex-1 min-w-0 font-medium";
    span.textContent = text;
    el.appendChild(icon);
    el.appendChild(span);
    el.className = `${TOAST_BASE} ${toastKind === "success" ? TOAST_SUCCESS_EXTRA : TOAST_ERROR_EXTRA}`;

    statusToastTimer = setTimeout(() => {
      TOAST_OUT.split(" ").forEach((c) => el.classList.add(c));
      statusToastOutTimer = setTimeout(() => {
        el.replaceChildren();
        el.className = STATUS_EL_DEFAULT;
        statusToastTimer = null;
        statusToastOutTimer = null;
        if (typeof options.onHide === "function") {
          try {
            options.onHide();
          } catch (e) {
            console.warn(e);
          }
        }
      }, STATUS_TOAST_OUT_MS);
    }, STATUS_TOAST_MS);
    return;
  }

  if (text) el.textContent = text;
}

/** @param {"success" | "error"} [kind] */
function setStatusThenClear(text, kind) {
  setStatus(text, { toast: kind === "error" ? "error" : "success" });
}

function getSelectedSuggestion(word, suggestions) {
  const list = suggestions || [];
  return selectedSuggestionByWord.get(word) ?? list[0] ?? null;
}

/** Англи (латин) үг эсэхийг шалгана — ийм үгийг алдаа шалгахгүй */
function isLatinOnly(word) {
  return LATIN_ONLY_REGEX.test(word);
}

/** ⚡ Кэшээс унших эсвэл Hunspell дуудаад кэшлэх. Буцах: { correct, suggestions? } */
function checkWord(word) {
  const cached = spellCache.get(word);
  if (cached !== undefined) return cached;
  const correct = spellChecker.spell(word);
  const entry = correct
    ? { correct: true }
    : { correct: false, suggestions: spellChecker.suggest(word) };
  spellCache.set(word, entry);
  return entry;
}

