/**
 * Сүүлд хийсэн шалгалтын статистик.
 * totalChecked: латин бус, шалгалтад орсон үгсийн нийт тоо.
 * totalErrors: алдаатай үгсийн давтамжтай нийлбэр.
 * topWords: [{ word, count }] (ихээс бага руу).
 * fixesApplied: «Засах» товчоор амжилттай солигдсон үгийн тоо (хуримтлал).
 */
let lastSpellStats = {
  totalChecked: 0,
  totalErrors: 0,
  topWords: [],
  fixesApplied: 0,
};

function saveSpellStats(stats) {
  try {
    localStorage.setItem(LS_SPELL_STATS, JSON.stringify(stats));
  } catch (e) {
    console.warn(e);
  }
}

function loadSpellStats() {
  try {
    const raw = localStorage.getItem(LS_SPELL_STATS);
    if (!raw) return null;
    return JSON.parse(raw);
  } catch {
    return null;
  }
}

/** @param {Map<string, number>} misspelledCounts */
function buildAndRenderSpellStats(totalChecked, misspelledCounts) {
  const topWords = Array.from(misspelledCounts.entries())
    .sort((a, b) => b[1] - a[1])
    .slice(0, 5)
    .map(([word, count]) => ({ word, count }));
  const totalErrors = Array.from(misspelledCounts.values()).reduce((a, b) => a + b, 0);
  const fixesApplied = Number(lastSpellStats.fixesApplied) || 0;

  lastSpellStats = {
    totalChecked,
    totalErrors,
    topWords,
    fixesApplied,
  };
  saveSpellStats(lastSpellStats);
  renderSpellStats();
}

function renderSpellStats() {
  const checkedEl = document.getElementById("stats-total-checked");
  const errorsEl = document.getElementById("stats-total-errors");
  const fixedEl = document.getElementById("stats-total-fixed");
  const topWordsEl = document.getElementById("stats-top-words");
  if (!checkedEl || !errorsEl || !topWordsEl) return;

  checkedEl.textContent = String(lastSpellStats.totalChecked || 0);
  errorsEl.textContent = String(lastSpellStats.totalErrors || 0);
  if (fixedEl) fixedEl.textContent = String(Number(lastSpellStats.fixesApplied) || 0);

  topWordsEl.replaceChildren();
  if (!lastSpellStats.topWords || lastSpellStats.topWords.length === 0) {
    const empty = document.createElement("span");
    empty.className = "text-[12.5px] text-slate-700 leading-relaxed";
    empty.textContent = "Одоогоор мэдээлэл алга.";
    topWordsEl.appendChild(empty);
    return;
  }

  lastSpellStats.topWords.forEach((x, idx) => {
    const chip = document.createElement("span");
    chip.className =
      "inline-flex items-center rounded-full border border-indigo-100 bg-indigo-50 px-3 py-1.5 text-xs font-semibold text-indigo-700";
    chip.textContent = `${idx + 1}. ${x.word} (${x.count})`;
    topWordsEl.appendChild(chip);
  });
}

