function formatPolarDateTime(iso) {
  if (iso == null || iso === "") return "—";
  const d = new Date(iso);
  if (Number.isNaN(d.getTime())) return String(iso);
  try {
    return new Intl.DateTimeFormat("mn-MN", {
      dateStyle: "medium",
      timeStyle: "short",
    }).format(d);
  } catch {
    return d.toLocaleString();
  }
}

function formatUsageLine(usage, limitUsage) {
  const u = usage == null ? "—" : String(usage);
  if (limitUsage != null && Number(limitUsage) > 0) {
    return `${u} / ${limitUsage}`;
  }
  return `${u} (хязгаар тодорхойгүй)`;
}

