function licenseBenefitMatches(data) {
  if (!POLAR_LICENSE_BENEFIT_ID) return true;
  return data && String(data.benefit_id || "") === POLAR_LICENSE_BENEFIT_ID;
}

function extractPolarErrorText(data, fallback) {
  if (!data) return fallback || "";
  if (typeof data.detail === "string") return data.detail;
  if (Array.isArray(data.detail)) {
    // Polar заримдаа detail-г { msg } хэлбэрээр array болгож өгдөг.
    return data.detail
      .map((d) => (d && (d.msg || d.message || d)) || "")
      .filter(Boolean)
      .join("; ");
  }
  if (typeof data.message === "string") return data.message;
  return fallback || "";
}

function getLicenseKeyValidationErrorMessage(res, data) {
  const status = res && typeof res.status === "number" ? res.status : null;
  const raw = extractPolarErrorText(data, status ? `Алдаа (${status})` : "Алдаа");
  const lower = String(raw).toLowerCase();

  // Түгээмэл Polar / backend алдааны хэлбэрүүдийг Mongoloор тааруулж харуулна.
  // Таны жишээ: { "error":"ResourceNotFound","detail":"License key is no longer active." }
  if (data && typeof data.error === "string" && data.error === "ResourceNotFound") {
    return "License key буруу байна.";
  }

  if (lower.includes("no longer") && lower.includes("active")) {
    return "License key хугацаа дууссан байна.";
  }
  if (lower.includes("inactive")) {
    return "License key идэвхтэй биш байна.";
  }
  if (lower.includes("disabled")) {
    return "License идэвхгүй байна. Дахин шалгана уу (эсвэл subscription/activation-аа шинэчил).";
  }
  if (
    lower.includes("invalid") ||
    lower.includes("not found") ||
    lower.includes("does not exist") ||
    lower.includes("wrong")
  ) {
    return "Таны оруулсан license key буруу байна. Дахин шалгана уу.";
  }
  if (lower.includes("expired")) {
    return "License хугацаа дууссан байна.";
  }
  if (lower.includes("revok") || lower.includes("canceled") || lower.includes("cancelled")) {
    return "License цуцлагдсан байна.";
  }
  if (lower.includes("activation") || lower.includes("activate")) {
    return "License ашигласан байна.";
  }

  // Benefit mismatch-ийг тусдаа шалгаж байгаа тул энд шууд raw-аа харуулахгүйгээр ерөнхийлөнө.
  return raw || "License баталгаажуулж чадсангүй.";
}

