function buildWordListFromDic(dicText) {
  const lines = dicText.split(/\r?\n/);
  const out = [];
  const seen = new Set();
  for (let i = 0; i < lines.length; i++) {
    const line = lines[i];
    if (i === 0 && /^\s*\d+\s*$/.test(line)) continue;
    if (!line || line.startsWith("#")) continue;
    const slash = line.indexOf("/");
    const raw = slash === -1 ? line : line.slice(0, slash);
    const word = raw.trim();
    if (word.length === 0) continue;
    if (seen.has(word)) continue;
    seen.add(word);
    out.push(word);
  }
  return out;
}

function normalizeForDictionarySearch(s) {
  try {
    return String(s).toLocaleLowerCase("mn-MN");
  } catch {
    return String(s).toLowerCase();
  }
}

/** Тэмдэгтүүдийн хоорондох зайгаар токенд хувааж, хоёр талын тусгай тэмдгийг авна */
function cleanTokenForSpell(t) {
  return String(t).replace(/^[^\p{L}\p{M}]+|[^\p{L}\p{M}]+$/gu, "");
}

/**
 * aff + dic-ийг Hunspell spell() дээр шууд ашиглана (нөхцөл/залгавараар зөвшөөрөгдсөн бүтэн үг).
 * Олон үг бол зайгаар тусгаарлагдсан бүрт шалгана.
 */
function getHunspellExactWordMatches(query) {
  if (!spellChecker) return [];
  const trimmed = String(query).trim();
  if (!trimmed) return [];
  const tokens = trimmed.split(/\s+/).filter(Boolean);
  const out = [];
  const seen = new Set();
  for (const raw of tokens) {
    const t = cleanTokenForSpell(raw);
    if (t.length < DICTIONARY_SEARCH_MIN_LEN) continue;
    try {
      if (spellChecker.spell(t)) {
        const key = normalizeForDictionarySearch(t);
        if (!seen.has(key)) {
          seen.add(key);
          out.push(t);
        }
      }
    } catch {
      /* ignore */
    }
  }
  return out;
}

