function runDictionarySearchNow() {
  const input = document.getElementById("dictionary-search-input");
  const resultsEl = document.getElementById("dictionary-search-results");
  if (!input || !resultsEl) return;

  if (!spellChecker) {
    renderDictionarySearchPlaceholder(
      "Толь бичиг ачаалагдаж байна. Түр хүлээнэ үү.",
      "text-sm text-slate-400"
    );
    return;
  }
  if (!dictionaryWordList || dictionaryWordList.length === 0) {
    renderDictionarySearchPlaceholder(
      "Үгийн сан бэлэн биш байна. Хуудсыг дахин ачаална уу.",
      "text-sm text-amber-700"
    );
    return;
  }
  if (!isLicenseActive()) {
    renderDictionarySearchPlaceholder(
      "Энэ боломж ашиглахын тулд Профайл хэсгээс license идэвхжүүлнэ үү.",
      "text-sm text-rose-600 leading-relaxed"
    );
    return;
  }

  const q = input.value.trim();
  if (q.length < DICTIONARY_SEARCH_MIN_LEN) {
    resultsEl.replaceChildren();
    const p = document.createElement("p");
    p.className = "text-sm text-slate-400";
    p.textContent = `Дор хаяж ${DICTIONARY_SEARCH_MIN_LEN} тэмдэгт оруулж хайна уу.`;
    resultsEl.appendChild(p);
    return;
  }

  const hunspellMatches = getHunspellExactWordMatches(q);
  const hsNorm = new Set(hunspellMatches.map((w) => normalizeForDictionarySearch(w)));

  const nq = normalizeForDictionarySearch(q);
  const dicMatches = [];
  for (let i = 0; i < dictionaryWordList.length; i++) {
    if (dicMatches.length >= DICTIONARY_SEARCH_MAX_RESULTS) break;
    const w = dictionaryWordList[i];
    const wn = normalizeForDictionarySearch(w);
    if (!wn.includes(nq)) continue;
    if (hsNorm.has(wn)) continue;
    dicMatches.push(w);
  }

  resultsEl.replaceChildren();
  if (hunspellMatches.length === 0 && dicMatches.length === 0) {
    const p = document.createElement("p");
    p.className = "text-sm text-slate-500";
    p.textContent = "Таны хайлттай таарах үг олдсонгүй.";
    resultsEl.appendChild(p);
    return;
  }

  if (hunspellMatches.length > 0) {
    const sub = document.createElement("p");
    sub.className = "text-[11px] font-semibold text-emerald-700 mb-2";
    sub.textContent = "Таарсан үг";
    resultsEl.appendChild(sub);
    const wrapHs = document.createElement("div");
    wrapHs.className = "flex flex-wrap gap-1.5 mb-4";
    hunspellMatches.forEach((w) => {
      const span = document.createElement("span");
      span.className =
        "inline-flex items-center rounded-lg border border-emerald-200 bg-emerald-50 px-2.5 py-1 text-[13px] font-medium text-emerald-900 break-all";
      span.textContent = w;
      wrapHs.appendChild(span);
    });
    resultsEl.appendChild(wrapHs);
  }

  if (dicMatches.length > 0) {
    const subDic = document.createElement("p");
    subDic.className = "text-[11px] font-medium text-slate-500 mb-2";
    subDic.textContent = "Үгийн сангаас таарсан ойролцоо үгс";
    resultsEl.appendChild(subDic);

    const hint = document.createElement("p");
    hint.className = "text-[11px] text-slate-400 mb-2.5";
    hint.textContent =
      dicMatches.length >= DICTIONARY_SEARCH_MAX_RESULTS
        ? `Эхний ${DICTIONARY_SEARCH_MAX_RESULTS} үг харуулж байна. Илүү нарийвчилж бичвэл илүү ойрхон олдоно.`
        : `${dicMatches.length} үг олдлоо.`;
    resultsEl.appendChild(hint);

    const wrap = document.createElement("div");
    wrap.className = "flex flex-wrap gap-1.5";
    dicMatches.forEach((w) => {
      const span = document.createElement("span");
      span.className =
        "inline-flex items-center rounded-lg border border-indigo-100 bg-indigo-50/90 px-2.5 py-1 text-[13px] font-medium text-indigo-900 break-all";
      span.textContent = w;
      wrap.appendChild(span);
    });
    resultsEl.appendChild(wrap);
  }
}

