function renderSuggestions(misspellingsMap) {
  const container = document.getElementById("suggestions");
  const empty = document.getElementById("suggestions-empty");
  if (!container || !empty) return;

  container.innerHTML = "";
  let entries = Array.from(misspellingsMap.entries()).filter(
    ([word, suggestions]) => !ignoredWords.has(word) && Array.isArray(suggestions) && suggestions.length > 0
  );
  entries = entries.sort(([a], [b]) => {
    const aNew = lastNewWords.has(a);
    const bNew = lastNewWords.has(b);
    if (aNew && !bNew) return -1;
    if (!aNew && bNew) return 1;
    const i = lastMisspellingOrder.indexOf(a);
    const j = lastMisspellingOrder.indexOf(b);
    if (i === -1 && j === -1) return 0;
    if (i === -1) return 1;
    if (j === -1) return -1;
    return i - j;
  });

  if (entries.length === 0) {
    empty.classList.remove("hidden");
    return;
  }

  empty.classList.add("hidden");

  for (const [word, suggestions] of entries) {
    const topSuggestions = (suggestions || []).slice(0, 8);
    const selected = getSelectedSuggestion(word, topSuggestions);

    const card = document.createElement("div");
    card.className =
      "bg-white rounded-2xl p-4 shadow-sm border border-slate-200/60 animate-card-in hover:shadow-md hover:-translate-y-0.5 transition-all duration-200";

    const header = document.createElement("div");
    header.className = "flex items-center gap-2 mb-3";
    header.innerHTML = `
      <span class="w-1 h-4 rounded-full bg-rose-500 shrink-0"></span>
      <span class="text-[13px] text-slate-400 font-medium flex-1">Алдаатай үг</span>
      <span class="text-base text-slate-300" aria-hidden="true"><i class="fa-solid fa-book"></i></span>
    `;
    card.appendChild(header);

    const row = document.createElement("div");
    row.className = "flex items-center gap-2.5 mb-3 flex-wrap";
    const wordSpan = document.createElement("span");
    wordSpan.className = "text-sm font-semibold text-slate-800";
    wordSpan.textContent = word;
    const arrowSpan = document.createElement("span");
    arrowSpan.className = "text-sm text-slate-300";
    arrowSpan.innerHTML = "<i class='fa-solid fa-arrow-right fa-fade' style='color: #6366f1;'></i>";
    const btnsWrap = document.createElement("div");
    btnsWrap.className = "flex flex-wrap gap-1.5";

    if (topSuggestions.length === 0) {
      const none = document.createElement("span");
      none.className = "text-[13px] text-slate-400 italic";
      none.textContent = "Санал олдсонгүй.";
      btnsWrap.appendChild(none);
    } else {
      for (const s of topSuggestions) {
        const btn = document.createElement("button");
        btn.type = "button";
        btn.className =
          s === selected
            ? "px-3 py-1.5 rounded-lg border border-indigo-500 bg-indigo-600 text-white text-[13px] font-medium cursor-pointer transition-all duration-150"
            : "px-3 py-1.5 rounded-lg border border-slate-200 bg-white text-[13px] text-slate-600 cursor-pointer hover:border-indigo-400 hover:bg-indigo-50 hover:text-indigo-600 transition-all duration-150";
        btn.textContent = s;
        btn.addEventListener("click", () => onCardSuggestionClick(word, topSuggestions, s));
        btnsWrap.appendChild(btn);
      }
    }
    row.appendChild(wordSpan);
    row.appendChild(arrowSpan);
    row.appendChild(btnsWrap);
    card.appendChild(row);

    const preview = document.createElement("div");
    preview.className = "mb-3 text-sm text-slate-600";
    const previewOld = document.createElement("span");
    previewOld.className = "line-through text-slate-300 mr-1";
    previewOld.textContent = word;
    const previewNew = document.createElement("span");
    previewNew.className = "font-semibold text-indigo-600";
    previewNew.textContent = selected || "";
    preview.appendChild(previewOld);
    preview.appendChild(previewNew);
    card.appendChild(preview);

    const actions = document.createElement("div");
    actions.className = "flex items-center gap-4";
    const acceptBtn = document.createElement("button");
    acceptBtn.type = "button";
    acceptBtn.className =
      "px-5 py-2 rounded-xl border-none bg-indigo-600 text-white text-sm font-semibold shadow-sm hover:bg-indigo-700 active:scale-[0.98] transition-all duration-150 disabled:opacity-50 disabled:cursor-not-allowed cursor-pointer";
    acceptBtn.textContent = "Засах";
    acceptBtn.disabled = !selected;
    acceptBtn.addEventListener("click", () => applyReplace(word, selected));
    const ignoreBtn = document.createElement("span");
    ignoreBtn.className =
      "text-sm text-slate-400 hover:text-slate-600 cursor-pointer transition-colors duration-150";
    ignoreBtn.textContent = "Алгасах";
    ignoreBtn.setAttribute("role", "button");
    ignoreBtn.tabIndex = 0;
    ignoreBtn.addEventListener("click", () => onIgnoreWord(word));
    ignoreBtn.addEventListener("keydown", (e) => {
      if (e.key === "Enter" || e.key === " ") {
        e.preventDefault();
        onIgnoreWord(word);
      }
    });
    actions.appendChild(acceptBtn);
    actions.appendChild(ignoreBtn);
    card.appendChild(actions);

    container.appendChild(card);
  }
}

function onIgnoreWord(word) {
  ignoredWords.add(word);
  selectedSuggestionByWord.delete(word);
  renderSuggestions(lastMisspellings);
}

function onCardSuggestionClick(word, suggestions, suggestion) {
  selectedSuggestionByWord.set(word, suggestion);
  renderSuggestions(lastMisspellings);
  if (currentHost === Office.HostType.Word) {
    Word.run(async (context) => {
      const body = context.document.body;
      const results = body.search(word, { matchWholeWord: true });
      results.load("items");
      await context.sync();
      if (results.items.length > 0) {
        results.items[0].select();
        await context.sync();
      }
    }).catch((e) => console.error("Үг рүү очиход алдаа:", e));
  }
}

async function applyReplace(fromWord, toWord) {
  if (!toWord) return;
  if (!isLicenseActive()) {
    setStatus("Эхлээд license key баталгаажуулна уу (Профайл).", { toast: "error" });
    return;
  }
  try {
    setStatusIcon("loading");
    setStatus(`"${fromWord}" → "${toWord}" солиж байна...`);

    if (currentHost === Office.HostType.Word) {
      await Word.run(async (context) => {
        const body = context.document.body;
        const results = body.search(fromWord, { matchWholeWord: true });
        results.load("items");
        await context.sync();

        let lastReplaced = null;
        results.items.forEach((r) => {
          const replaced = r.insertText(toWord, Word.InsertLocation.replace);
          r.font.highlightColor = null;
          replaced.font.highlightColor = null;
          lastReplaced = replaced;
        });
        await context.sync();
        if (lastReplaced) {
          const afterRange = lastReplaced.getRange(Word.RangeLocation.after);
          afterRange.select();
          await context.sync();
        }
      });
      // Word дээр "бүх текст"-ийг cache дээрээ шинээр тооцоолохгүй, зөвхөн хурдан update хийе.
      lastBodyText = lastBodyText.replace(new RegExp(escapeRegex(fromWord), "g"), toWord);
    } else if (currentHost === Office.HostType.Excel) {
      await Excel.run(async (context) => {
        const sheets = context.workbook.worksheets;
        sheets.load("items");
        await context.sync();

        for (const sheet of sheets.items) {
          const usedRange = sheet.getUsedRange(true);
          usedRange.load("values");
          await context.sync();

          const values = usedRange.values;
          for (let r = 0; r < values.length; r++) {
            for (let c = 0; c < values[r].length; c++) {
              const v = values[r][c];
              if (typeof v === "string" && v) {
                values[r][c] = replaceWholeWord(v, fromWord, toWord);
              }
            }
          }
          usedRange.values = values;
        }
        await context.sync();
      });
    } else if (currentHost === Office.HostType.PowerPoint) {
      await PowerPoint.run(async (context) => {
        const slides = context.presentation.slides;
        slides.load("items");
        await context.sync();

        for (const slide of slides.items) {
          const shapes = slide.shapes;
          shapes.load("items");
          await context.sync();

          // Багцаар text property-г preload хийнэ.
          shapes.items.forEach((shape) => {
            shape.load("textFrame/textRange/text");
          });
          await context.sync();

          shapes.items.forEach((shape) => {
            const text = shape?.textFrame?.textRange?.text;
            if (typeof text === "string" && text) {
              shape.textFrame.textRange.text = replaceWholeWord(text, fromWord, toWord);
            }
          });
        }

        await context.sync();
      });
    } else {
      throw new Error(`Unsupported host: ${currentHost}`);
    }

    lastSpellStats.fixesApplied = (Number(lastSpellStats.fixesApplied) || 0) + 1;
    saveSpellStats(lastSpellStats);
    renderSpellStats();

    setStatusIcon("success");
    setStatus(`"${fromWord}" үг засагдлаа.`, {
      toast: "success",
      onHide: () => setStatusIcon("ready"),
    });
    lastMisspellings.delete(fromWord);
    lastMisspellingOrder = lastMisspellingOrder.filter((w) => w !== fromWord);
    lastOccurrenceIndex.delete(fromWord);
    lastNewWords.delete(fromWord);
    selectedSuggestionByWord.delete(fromWord);
    renderSuggestions(lastMisspellings);
    setTimeout(() => run(), 0);
  } catch (e) {
    console.error("Засах үед алдаа гарлаа:", e);
    setStatusIcon("error");
    setStatus("Засах үед алдаа гарлаа.", {
      toast: "error",
      onHide: () => setStatusIcon("ready"),
    });
  }
}

function escapeRegex(s) {
  return s.replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
}

function makeWholeWordRegex(word) {
  // Латин/орос гэх мэт аль ч үгийн ар/урд талд зөвхөн үсэг/тэмдэг (L/M) байвал хил гэж үзнэ.
  // Ингэснээр "word" нь bigger token дотроо таарахгүй (whole word).
  const escaped = escapeRegex(word);
  return new RegExp(`(^|[^\\p{L}\\p{M}])${escaped}([^\\p{L}\\p{M}]|$)`, "gu");
}

function replaceWholeWord(text, fromWord, toWord) {
  if (typeof text !== "string" || !text) return text;
  const re = makeWholeWordRegex(fromWord);
  return text.replace(
    re,
    (_m, leftDelim, rightDelim) => `${leftDelim ?? ""}${toWord}${rightDelim ?? ""}`
  );
}

/** Гүйлгэхэд доод баруун буланд «дээш буцах» товч */
const SCROLL_TOP_SHOW_PX = 100;

function getScrollY() {
  return (
    window.scrollY ??
    window.pageYOffset ??
    document.documentElement.scrollTop ??
    document.body.scrollTop ??
    0
  );
}

function initScrollToTopButton() {
  const btn = document.getElementById("scroll-top-btn");
  if (!btn) return;

  const update = () => {
    btn.classList.toggle("hidden", getScrollY() < SCROLL_TOP_SHOW_PX);
  };

  window.addEventListener("scroll", update, { passive: true });
  btn.addEventListener("click", () => {
    window.scrollTo({ top: 0, behavior: "smooth" });
  });
  update();
}

/** Fixed header-ийн өндөр + main дээд зай (өмнө нь pt-4 ≈ 16px) */
const FIXED_HEADER_MAIN_GAP_PX = 16;

function initFixedHeaderMainPadding() {
  const header = document.querySelector("header");
  const main = document.getElementById("main-content") || document.querySelector("main");
  if (!header || !main) return;
  const apply = () => {
    main.style.paddingTop = `${header.offsetHeight + FIXED_HEADER_MAIN_GAP_PX}px`;
  };
  apply();
  const ro = new ResizeObserver(apply);
  ro.observe(header);
}

