async function loadDictionary() {
  try {
    console.log("Толь бичиг ачаалж байна...");

    // Lazy-load hunspell-asm only when needed
    const { loadModule } = await import("hunspell-asm");

    // 1. Файлуудыг ArrayBuffer хэлбэрээр татаж авах
    const [affRes, dicRes] = await Promise.all([fetch(affUrl), fetch(dicUrl)]);

    const affBuffer = new Uint8Array(await affRes.arrayBuffer());
    const dicBuffer = new Uint8Array(await dicRes.arrayBuffer());

    // 2. Hunspell wasm module-г ачаалж, factory авах
    const factory = await loadModule();

    // 3. aff/dic файлуудыг wasm FS руу mount хийгээд spellchecker үүсгэх
    const affPath = factory.mountBuffer(affBuffer, "mn_MN.aff");
    const dicPath = factory.mountBuffer(dicBuffer, "mn_MN.dic");
    spellChecker = factory.create(affPath, dicPath);

    try {
      const dicText = new TextDecoder("utf-8").decode(dicBuffer);
      dictionaryWordList = buildWordListFromDic(dicText);
      console.log("Үгийн сангийн нийт үг:", dictionaryWordList.length);
    } catch (e) {
      console.warn("Үгийн жагсаалт үүсгэхэд алдаа:", e);
      dictionaryWordList = [];
    }
    if (currentView === "search") queueMicrotask(() => runDictionarySearchNow());

    console.log("Монгол хэлний толь амжилттай уншигдлаа!");
    if (isLicenseActive()) {
      setStatus("Алдаа шалгахад бэлэн.", {
        toast: "success",
        onHide: () => setStatusIcon("ready"),
      });
      if (currentHost === Office.HostType.Word) startAutoSpellCheck();
    } else {
      setStatus("Төлбөр төлөх эсвэл License key оруулж баталгаажуулна уу!", {
        toast: "error",
        onHide: () => setStatusIcon("ready"),
      });
    }
  } catch (error) {
    console.error("Алдаа гарлаа:", error);
    setStatusIcon("error");
    setStatus("Толь уншихад алдаа гарлаа.", {
      toast: "error",
      onHide: () => setStatusIcon("ready"),
    });
  }
}

let textCheckTimer = null;

function startAutoSpellCheck() {
  if (!isAutoSpellCheckEnabled()) return;
  if (textCheckTimer) return;
  if (currentHost !== Office.HostType.Word) return;
  if (!isLicenseActive()) return;
  run();
  textCheckTimer = setInterval(async () => {
    if (!isLicenseActive() || !spellChecker) return;
    try {
      const currentText = await Word.run(async (context) => {
        const body = context.document.body;
        body.load("text");
        await context.sync();
        return body.text;
      });
      if (currentText !== lastBodyText) run();
    } catch (e) {
      console.error("Текст шалгахад алдаа:", e);
    }
  }, TEXT_CHECK_INTERVAL_MS);
}

export async function run() {
  if (!isLicenseActive()) {
    setStatusIcon("error");
    setStatus("License шаардлагатай (Профайл).", {
      toast: "error",
      onHide: () => setStatusIcon("ready"),
    });
    return;
  }
  setStatusIcon("loading");

  if (!spellChecker) {
    console.error("Толь бичиг хараахан ачаалж дуусаагүй байна.");
    setStatusIcon("error");
    setStatus("Толь бичиг хараахан ачаалж дуусаагүй байна.", {
      toast: "error",
      onHide: () => setStatusIcon("ready"),
    });
    return;
  }

  const host = currentHost;
  if (host === Office.HostType.Word) {
    return Word.run(async (context) => {
      const body = context.document.body;
      body.load("text");
      await context.sync();

      const currentText = body.text;
      if (currentText === lastBodyText) {
        setStatusIcon("ready");
        return;
      }
      lastBodyText = currentText;
      const wordsInOrder = (currentText.match(WORD_REGEX) || []).filter((w) => w.length > 1);
      const misspellings = new Map();
      const seen = new Set();
      const occurrenceIndex = new Map();
      const misspelledCounts = new Map();
      let totalChecked = 0;

      for (let i = 0; i < wordsInOrder.length; i++) {
        const word = wordsInOrder[i];
        if (isLatinOnly(word)) {
          seen.add(word);
          continue;
        }
        totalChecked++;
        if (!seen.has(word)) {
          seen.add(word);
          const { correct, suggestions } = checkWord(word);
          if (!correct) {
            misspellings.set(word, suggestions || []);
            occurrenceIndex.set(word, i);
            misspelledCounts.set(word, 1);
          }
        } else if (misspellings.has(word)) {
          occurrenceIndex.set(word, i);
          misspelledCounts.set(word, (misspelledCounts.get(word) || 0) + 1);
        }
      }

      const prevKeys = new Set(lastMisspellings.keys());
      lastMisspellings = misspellings;
      lastOccurrenceIndex = occurrenceIndex;
      lastMisspellingOrder = [...misspellings.keys()].sort(
        (a, b) => (occurrenceIndex.get(b) ?? 0) - (occurrenceIndex.get(a) ?? 0)
      );
      lastNewWords = new Set(lastMisspellingOrder.filter((w) => !prevKeys.has(w)));
      renderSuggestions(lastMisspellings);
      buildAndRenderSpellStats(totalChecked, misspelledCounts);
      console.log("Олдсон алдаанууд:", Array.from(misspellings.keys()));
      setStatusIcon("ready");
      await context.sync();
    }).catch((err) => {
      console.error("Алдаа шалгахад алдаа:", err);
      setStatusIcon("error");
      setStatus("Алдаа шалгахад алдаа гарлаа.", {
        toast: "error",
        onHide: () => setStatusIcon("ready"),
      });
    });
  }

  if (host === Office.HostType.Excel) {
    return Excel.run(async (context) => {
      const sheets = context.workbook.worksheets;
      sheets.load("items");
      await context.sync();

      const misspellings = new Map();
      const seen = new Set();
      const occurrenceIndex = new Map();
      const misspelledCounts = new Map();
      let wordIndex = 0; // workbook дахь үгний уншилтын дараалал
      let totalChecked = 0;

      for (const sheet of sheets.items) {
        const usedRange = sheet.getUsedRange(true);
        usedRange.load("values");
        await context.sync();

        const values = usedRange.values || [];
        for (let r = 0; r < values.length; r++) {
          for (let c = 0; c < (values[r] || []).length; c++) {
            const v = values[r][c];
            const text = typeof v === "string" ? v : v == null ? "" : String(v);
            const wordsInOrder = (text.match(WORD_REGEX) || []).filter((w) => w.length > 1);
            for (let i = 0; i < wordsInOrder.length; i++) {
              const word = wordsInOrder[i];
              if (isLatinOnly(word)) {
                seen.add(word);
                wordIndex++;
                continue;
              }
              totalChecked++;

              if (!seen.has(word)) {
                seen.add(word);
                const { correct, suggestions } = checkWord(word);
                if (!correct) {
                  misspellings.set(word, suggestions || []);
                  occurrenceIndex.set(word, wordIndex);
                  misspelledCounts.set(word, 1);
                }
              } else if (misspellings.has(word)) {
                occurrenceIndex.set(word, wordIndex);
                misspelledCounts.set(word, (misspelledCounts.get(word) || 0) + 1);
              }
              wordIndex++;
            }
          }
        }
      }

      const prevKeys = new Set(lastMisspellings.keys());
      lastMisspellings = misspellings;
      lastOccurrenceIndex = occurrenceIndex;
      lastMisspellingOrder = [...misspellings.keys()].sort(
        (a, b) => (occurrenceIndex.get(b) ?? 0) - (occurrenceIndex.get(a) ?? 0)
      );
      lastNewWords = new Set(lastMisspellingOrder.filter((w) => !prevKeys.has(w)));
      renderSuggestions(lastMisspellings);
      buildAndRenderSpellStats(totalChecked, misspelledCounts);
      console.log("Олдсон алдаанууд:", Array.from(misspellings.keys()));
      setStatusIcon("ready");
      await context.sync();
    }).catch((err) => {
      console.error("Алдаа шалгахад алдаа:", err);
      setStatusIcon("error");
      setStatus("Алдаа шалгахад алдаа гарлаа.", {
        toast: "error",
        onHide: () => setStatusIcon("ready"),
      });
    });
  }

  if (host === Office.HostType.PowerPoint) {
    return PowerPoint.run(async (context) => {
      const slides = context.presentation.slides;
      slides.load("items");
      await context.sync();

      const misspellings = new Map();
      const seen = new Set();
      const occurrenceIndex = new Map();
      const misspelledCounts = new Map();
      let wordIndex = 0; // slide-шиг уншилтын дараалал
      let totalChecked = 0;

      for (const slide of slides.items) {
        const shapes = slide.shapes;
        shapes.load("items");
        await context.sync();

        shapes.items.forEach((shape) => {
          shape.load("textFrame/textRange/text");
        });
        await context.sync();

        shapes.items.forEach((shape) => {
          const text = shape?.textFrame?.textRange?.text;
          if (typeof text !== "string" || !text) return;
          const wordsInOrder = (text.match(WORD_REGEX) || []).filter((w) => w.length > 1);
          for (let i = 0; i < wordsInOrder.length; i++) {
            const word = wordsInOrder[i];
            if (isLatinOnly(word)) {
              seen.add(word);
              wordIndex++;
              continue;
            }
            totalChecked++;

            if (!seen.has(word)) {
              seen.add(word);
              const { correct, suggestions } = checkWord(word);
              if (!correct) {
                misspellings.set(word, suggestions || []);
                occurrenceIndex.set(word, wordIndex);
                misspelledCounts.set(word, 1);
              }
            } else if (misspellings.has(word)) {
              occurrenceIndex.set(word, wordIndex);
              misspelledCounts.set(word, (misspelledCounts.get(word) || 0) + 1);
            }
            wordIndex++;
          }
        });
      }

      const prevKeys = new Set(lastMisspellings.keys());
      lastMisspellings = misspellings;
      lastOccurrenceIndex = occurrenceIndex;
      lastMisspellingOrder = [...misspellings.keys()].sort(
        (a, b) => (occurrenceIndex.get(b) ?? 0) - (occurrenceIndex.get(a) ?? 0)
      );
      lastNewWords = new Set(lastMisspellingOrder.filter((w) => !prevKeys.has(w)));
      renderSuggestions(lastMisspellings);
      buildAndRenderSpellStats(totalChecked, misspelledCounts);
      console.log("Олдсон алдаанууд:", Array.from(misspellings.keys()));
      setStatusIcon("ready");
      await context.sync();
    }).catch((err) => {
      console.error("Алдаа шалгахад алдаа:", err);
      setStatusIcon("error");
      setStatus("Алдаа шалгахад алдаа гарлаа.", {
        toast: "error",
        onHide: () => setStatusIcon("ready"),
      });
    });
  }

  setStatusIcon("error");
  setStatus("Энэ host дээр хараахан дэмжигдээгүй байна.", { toast: "error" });
}
